import { useState, useRef } from "react";
import { useNavigate, useParams } from "react-router-dom";
import { useData } from "../contexts/DataContext";
import { Button } from "../components/ui/button";
import { Dialog, DialogContent } from "../components/ui/dialog";
import { FolderUp, X, CheckCircle2 } from "lucide-react";
import { toast } from "sonner";

export default function UpInvoice() {
  const { id } = useParams();
  const { orders = [], setInvoiceUploaded } = useData();
  const navigate = useNavigate();

  const fileInputRef = useRef(null);

  const order = orders.find((o) => String(o.id) === id);

  const [file, setFile] = useState(null);
  const [dragOver, setDragOver] = useState(false);
  const [showSuccess, setShowSuccess] = useState(false);
  const [loading, setLoading] = useState(false);

  if (!order) {
    return (
      <div>
        <p className="text-gray-500">Pesanan tidak ditemukan.</p>
        <Button
          onClick={() => navigate("/status-pengiriman")}
          className="mt-4"
        >
          Kembali
        </Button>
      </div>
    );
  }

  const handleFile = (f) => {
    if (!f) return;

    const validType =
      f.type === "application/pdf" || f.type === "image/png";

    if (!validType) {
      toast.error("File harus PDF atau PNG");
      return;
    }

    setFile(f);
  };

  const handleSubmit = async () => {
    if (!file) {
      toast.error("Pilih file terlebih dahulu");
      return;
    }

    try {
      setLoading(true);

      // simulasi upload
      await new Promise((res) => setTimeout(res, 800));

      setInvoiceUploaded(order.id);
      setShowSuccess(true);
    } catch (err) {
      toast.error("Gagal upload invoice");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="max-w-[900px]" data-testid="up-invoice-page">
      <h1 className="text-3xl font-extrabold text-gray-900">
        Invoice
      </h1>
      <h2 className="text-3xl font-extrabold text-[#F59E0B] mt-1">
        #{order.id}
      </h2>

      <p className="text-sm text-gray-600 mt-3 mb-7">
        Kirim invoice ke customer
      </p>

      <div className="mpl-card p-8">
        <div className="flex items-start justify-between">
          <h3 className="text-lg font-bold text-gray-900">
            Kirim Invoice
          </h3>

          <button
            onClick={() => navigate(-1)}
            className="text-gray-400 hover:text-gray-600"
          >
            <X className="w-5 h-5" />
          </button>
        </div>

        {/* UPLOAD ZONE */}
        <div
          onClick={() => fileInputRef.current?.click()}
          onDragOver={(e) => {
            e.preventDefault();
            setDragOver(true);
          }}
          onDragLeave={() => setDragOver(false)}
          onDrop={(e) => {
            e.preventDefault();
            setDragOver(false);
            handleFile(e.dataTransfer.files?.[0]);
          }}
          className={`mt-6 border-2 border-dashed rounded-xl p-12 text-center cursor-pointer transition ${
            dragOver
              ? "border-[#F59E0B] bg-[#FEF3C7]/40"
              : "border-[#F59E0B]/60 bg-orange-50/30"
          }`}
        >
          <div className="flex flex-col items-center gap-3">
            <FolderUp className="w-8 h-8 text-[#F59E0B]" />

            <div className="text-sm font-medium text-gray-700">
              {file ? file.name : "Klik atau drag file ke sini"}
            </div>

            {file && (
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  setFile(null);
                }}
                className="text-xs text-red-500"
              >
                Hapus file
              </button>
            )}
          </div>

          <input
            ref={fileInputRef}
            type="file"
            accept=".pdf,.png"
            hidden
            onChange={(e) =>
              handleFile(e.target.files?.[0])
            }
          />
        </div>

        <p className="text-xs text-gray-500 mt-3">
          Format: PDF / PNG
        </p>

        {/* ACTION */}
        <div className="flex justify-end gap-3 mt-6">
          <Button
            variant="outline"
            onClick={() => navigate(-1)}
          >
            Kembali
          </Button>

          <Button
            onClick={handleSubmit}
            disabled={!file || loading}
            className="mpl-btn-primary"
          >
            {loading ? "Mengirim..." : "Kirim"}
          </Button>
        </div>
      </div>

      {/* SUCCESS */}
      <Dialog open={showSuccess} onOpenChange={setShowSuccess}>
        <DialogContent className="max-w-md text-center py-12">
          <div className="flex flex-col items-center gap-4">
            <CheckCircle2 className="w-12 h-12 text-emerald-500" />

            <div className="text-lg font-bold">
              Invoice Berhasil Terkirim
            </div>

            <Button
              onClick={() => navigate("/status-pengiriman")}
              className="mpl-btn-primary mt-3"
            >
              Selesai
            </Button>
          </div>
        </DialogContent>
      </Dialog>
    </div>
  );
}
